 multianual.</strong></p>","_id":"1af1250"}],"border_width":{"unit":"px","size":0,"sizes":[]},"title_color":"#000000","tab_active_color":"#000000","_padding":{"unit":"%","top":"0","right":"0","bottom":"0","left":"0","isLinked":false},"_padding_tablet":{"unit":"%","top":"","right":"","bottom":"","left":"","isLinked":true},"_padding_mobile":{"unit":"%","top":"","right":"","bottom":"","left":"","isLinked":true},"_flex_align_self":"center","_border_border":"solid","_border_width":{"unit":"px","top":"1","right":"0","bottom":"0","left":"0","isLinked":false},"_border_color":"#BEBCBC","eael_wrapper_link_switch":"","eael_wrapper_link":{"url":"","is_external":"","nofollow":"","custom_attributes":""},"cpel_lv_enabled":"","cpel_lv_action":"show","cpel_lv_languages":[]},"elements":[],"widgetType":"toggle"},{"id":"49160231","elType":"widget","settings":{"tabs":[{"tab_title":"Ventajas y desventajas","tab_content":"<table class="custom-table"><thead><tr><td class="ventajas">Ventajas</td><td class="desventajas">Desventajas</td></tr></thead><tbody><tr><td><ul><li>Gran trayectoria.</li></ul></td><td><ul><li>Algunas herramientas funcionan mejor en otras plataformas.</li></ul></td></tr><tr><td><ul><li>Disponible en los 50 estados, incluyendo Columbia, Virgin Islands y Puerto Rico.</li></ul></td><td><ul><li>El funcionamiento de la página es algo lento.</li></ul></td></tr><tr><td><ul><li>Precios razonables acorde a los servicios.</li></ul></td><td><div> </div></td></tr></tbody></table>","_id":"1af1250"}],"border_width":{"unit":"px","size":0,"sizes":[]},"title_color":"#000000","tab_active_color":"#000000","_padding":{"unit":"%","top":"0","right":"0","bottom":"0","left":"0","isLinked":false},"_padding_tablet":{"unit":"%","top":"","right":"","bottom":"","left":"","isLinked":true},"_padding_mobile":{"unit":"%","top":"","right":"","bottom":"","left":"","isLinked":true},"_flex_align_self":"center","_border_border":"solid","_border_width":{"unit":"px","top":"1","right":"0","bottom":"0","left":"0